WITH src AS (SELECT e.oid AS extension_id, e.extname AS extension_name, a.rolname AS extension_owner, a.rolsuper AS is_super_user, n.nspname AS extension_schema, e.extrelocatable AS is_relocatable, e.extversion AS extension_version, CURRENT_DATABASE() AS database_name, CAST(e.extconfig AS TEXT) AS extension_config, CAST(e.extcondition AS TEXT) AS extension_condition FROM pg_extension AS e JOIN pg_roles AS a ON (e.extowner = a.oid) JOIN pg_namespace AS n ON (e.extnamespace = n.oid)) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.extension_id, src.extension_name, src.extension_owner, src.extension_schema, src.is_relocatable, src.extension_version, CHR(34) || src.database_name || CHR(34) AS database_name, src.is_super_user, src.extension_config, src.extension_condition FROM src